"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";

// ===== 常量 =====
const UNIT = 20; // 每单位 20px
const BAR_W = 40; // 条形宽度 40px

// 练习 1：画条形图 —— 水果数据 🍎5 🍌3 🍇4 🍊2
const FRUITS = [
  { emoji: "🍎", name: "苹果", target: 5, color: "var(--accent)" },
  { emoji: "🍌", name: "香蕉", target: 3, color: "var(--primary)" },
  { emoji: "🍇", name: "葡萄", target: 4, color: "var(--accent2)" },
  { emoji: "🍊", name: "橘子", target: 2, color: "var(--accent3)" },
] as const;

// 练习 2：读条形图 —— 宠物数据 🐶4 🐱3 🐰2 🐟5
const PETS = [
  { emoji: "🐶", name: "狗", value: 4, color: "var(--accent)" },
  { emoji: "🐱", name: "猫", value: 3, color: "var(--primary)" },
  { emoji: "🐰", name: "兔", value: 2, color: "var(--accent2)" },
  { emoji: "🐟", name: "鱼", value: 5, color: "var(--accent3)" },
] as const;

interface BarItem {
  emoji: string;
  name: string;
  value: number;
  color: string;
  target?: number;
}

// ===== 条形图 SVG 组件 =====
function BarChart({
  items,
  maxScale = 5,
  animate = false,
}: {
  items: BarItem[];
  maxScale?: number;
  animate?: boolean;
}) {
  const baselineY = 180; // X 轴所在 y
  const startX = 64; // 第一根条形 x
  const gap = 24; // 条形间距

  return (
    <svg
      viewBox="0 0 340 240"
      className="w-full"
      style={{ maxHeight: 300 }}
      role="img"
      aria-label="条形统计图"
    >
      {/* 网格线 + Y 轴刻度 */}
      {Array.from({ length: maxScale + 1 }).map((_, i) => {
        const y = baselineY - i * UNIT;
        return (
          <g key={i}>
            <line
              x1={40}
              y1={y}
              x2={320}
              y2={y}
              stroke={i === 0 ? "var(--text-secondary)" : "var(--border)"}
              strokeWidth={i === 0 ? 1.5 : 1}
              strokeDasharray={i === 0 ? "0" : "3 3"}
            />
            <text
              x={32}
              y={y + 4}
              fontSize={12}
              fill="var(--text-muted)"
              textAnchor="end"
            >
              {i}
            </text>
          </g>
        );
      })}

      {/* Y 轴 */}
      <line
        x1={40}
        y1={baselineY - maxScale * UNIT}
        x2={40}
        y2={baselineY}
        stroke="var(--text-secondary)"
        strokeWidth={1.5}
      />

      {/* 条形 */}
      {items.map((item, i) => {
        const x = startX + i * (BAR_W + gap);
        const h = item.value * UNIT;
        const y = baselineY - h;
        const target = item.target ?? item.value;
        const showTarget = target > item.value;
        return (
          <g key={i}>
            {/* 目标轮廓（虚线引导） */}
            {showTarget && (
              <rect
                x={x}
                y={baselineY - target * UNIT}
                width={BAR_W}
                height={target * UNIT}
                rx={6}
                fill="none"
                stroke={item.color}
                strokeWidth={1.5}
                strokeDasharray="4 4"
                opacity={0.35}
              />
            )}
            {/* 实际条形 */}
            {item.value > 0 && (
              <rect
                x={x}
                y={y}
                width={BAR_W}
                height={h}
                rx={6}
                fill={item.color}
                style={
                  animate
                    ? { transition: "y 0.35s ease, height 0.35s ease" }
                    : undefined
                }
              />
            )}
            {/* 数值标签 */}
            {item.value > 0 && (
              <text
                x={x + BAR_W / 2}
                y={y - 6}
                fontSize={13}
                fontWeight="bold"
                fill="var(--text)"
                textAnchor="middle"
              >
                {item.value}
              </text>
            )}
            {/* X 轴 emoji */}
            <text
              x={x + BAR_W / 2}
              y={206}
              fontSize={20}
              textAnchor="middle"
            >
              {item.emoji}
            </text>
            <text
              x={x + BAR_W / 2}
              y={224}
              fontSize={11}
              fill="var(--text-secondary)"
              textAnchor="middle"
            >
              {item.name}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

// ===== 读图题目 =====
const QUESTIONS = [
  {
    prompt: "哪种宠物最多？",
    hint: "看哪根条形最高，就是最多的！",
    options: [
      { label: "A. 狗", correct: false },
      { label: "B. 猫", correct: false },
      { label: "C. 兔", correct: false },
      { label: "D. 鱼", correct: true },
    ],
  },
  {
    prompt: "狗有几只？",
    hint: "找到 🐶 的条形，看它顶部对着数字几。",
    options: [
      { label: "A. 3", correct: false },
      { label: "B. 4", correct: true },
      { label: "C. 5", correct: false },
      { label: "D. 2", correct: false },
    ],
  },
  {
    prompt: "猫比兔多几只？",
    hint: "猫 3 只，兔 2 只，3 - 2 = ？",
    options: [
      { label: "A. 1", correct: true },
      { label: "B. 2", correct: false },
      { label: "C. 3", correct: false },
      { label: "D. 4", correct: false },
    ],
  },
] as const;

// ===== 主组件 =====
type Phase = "draw" | "read" | "done";

export default function DrawPage() {
  const [phase, setPhase] = useState<Phase>("draw");

  // 练习 1 状态
  const [values, setValues] = useState<number[]>([0, 0, 0, 0]);
  const [current, setCurrent] = useState(0);
  const [drawDone, setDrawDone] = useState(false);

  // 练习 2 状态
  const [qIndex, setQIndex] = useState(0);
  const [encourage, setEncourage] = useState<string | null>(null);
  const questionRef = useRef<HTMLDivElement>(null);

  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const nextStep = getNextStep("data", "draw");

  // 练习 1：画一条
  const handleDrawOne = () => {
    if (drawDone || current >= FRUITS.length) return;
    const newValues = [...values];
    newValues[current] = Math.min(values[current] + 1, FRUITS[current].target);
    setValues(newValues);
    if (newValues[current] >= FRUITS[current].target) {
      if (current === FRUITS.length - 1) {
        setDrawDone(true);
      } else {
        setTimeout(() => setCurrent((c) => c + 1), 380);
      }
    }
  };

  // 练习 2：答题
  const handleAnswer = (correct: boolean) => {
    if (correct) {
      setEncourage(null);
      if (qIndex < QUESTIONS.length - 1) {
        setQIndex(qIndex + 1);
      } else {
        setPhase("done");
      }
    } else {
      triggerShake(questionRef.current);
      setEncourage(getRandomEncourage());
    }
  };

  const resetAll = () => {
    setPhase("draw");
    setValues([0, 0, 0, 0]);
    setCurrent(0);
    setDrawDone(false);
    setQIndex(0);
    setEncourage(null);
  };

  const drawItems: BarItem[] = FRUITS.map((f, i) => ({
    emoji: f.emoji,
    name: f.name,
    value: values[i],
    color: f.color,
    target: f.target,
  }));
  const petItems: BarItem[] = PETS.map((p) => ({
    emoji: p.emoji,
    name: p.name,
    value: p.value,
    color: p.color,
  }));

  return (
    <StepShell topicId="data" stepId="draw">
      <div className="space-y-6">
        {/* 情境说明 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
          <p className="text-[var(--text)]">
            📊 把数据画成条形图，一眼就能看出谁多谁少！
          </p>
        </div>

        {/* ===== 练习 1：画条形图 ===== */}
        {phase === "draw" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--accent)]">练习 1 / 2</p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                画条形图
              </h2>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                数据：🍎 5 人　🍌 3 人　🍇 4 人　🍊 2 人
              </p>
            </div>

            {/* 数据卡片 */}
            <div className="mt-4 grid grid-cols-4 gap-2">
              {FRUITS.map((f, i) => {
                const active = current === i && !drawDone;
                return (
                  <div
                    key={f.name}
                    className="rounded-xl border p-2 text-center transition-all"
                    style={{
                      borderColor: active ? f.color : "var(--border)",
                      borderWidth: active ? 2 : 1,
                      backgroundColor: active
                        ? `color-mix(in srgb, ${f.color} 12%, transparent)`
                        : "var(--bg-card)",
                    }}
                  >
                    <div className="text-2xl">{f.emoji}</div>
                    <div className="text-xs text-[var(--text-secondary)]">
                      {f.name}
                    </div>
                    <div className="text-sm font-bold" style={{ color: f.color }}>
                      {values[i]} / {f.target}
                    </div>
                  </div>
                );
              })}
            </div>

            {/* 条形图 */}
            <div className="mt-5 rounded-xl bg-[var(--bg-soft)] p-3">
              <BarChart items={drawItems} maxScale={5} animate />
            </div>

            {/* 操作区 */}
            {!drawDone ? (
              <div className="mt-5 flex flex-col items-center gap-2">
                <p className="text-sm text-[var(--text-secondary)]">
                  {current < FRUITS.length ? (
                    <>
                      现在画{" "}
                      <span className="text-2xl align-middle">
                        {FRUITS[current].emoji}
                      </span>
                      <strong className="mx-1">{FRUITS[current].name}</strong>
                      ：已画 {values[current]} / {FRUITS[current].target}
                    </>
                  ) : (
                    "全部画完啦！"
                  )}
                </p>
                <button
                  onClick={handleDrawOne}
                  disabled={current >= FRUITS.length}
                  className="rounded-full px-8 py-3 font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105 disabled:cursor-not-allowed disabled:opacity-30"
                  style={{ backgroundColor: "var(--accent)" }}
                >
                  画一条 +1
                </button>
                <p className="text-xs text-[var(--text-muted)]">
                  💡 每点一次，条形就长高一格（一格代表 1 人）
                </p>
              </div>
            ) : (
              <div className="mt-5 flex flex-col items-center gap-3 animate-float-in">
                <div className="rounded-xl border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 px-6 py-3 text-center">
                  <p className="font-bold text-[var(--signal-success)]">
                    ✓ 条形图完成！
                  </p>
                  <p className="mt-1 text-xs text-[var(--text-secondary)]">
                    苹果 5、香蕉 3、葡萄 4、橘子 2
                  </p>
                </div>
                <button
                  onClick={() => setPhase("read")}
                  className="rounded-full bg-[var(--accent)] px-6 py-3 font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一题：读条形图 →
                </button>
              </div>
            )}
          </section>
        )}

        {/* ===== 练习 2：读条形图 ===== */}
        {phase === "read" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--primary)]">
                练习 2 / 2
              </p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                读条形图
              </h2>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                看看同学们最喜欢的宠物，回答下面的问题
              </p>
            </div>

            <div className="mt-4 rounded-xl bg-[var(--bg-soft)] p-3">
              <BarChart items={petItems} maxScale={5} />
            </div>

            {/* 题目 */}
            <div
              ref={questionRef}
              className="mt-5 rounded-xl border-2 border-[var(--primary)] bg-[var(--primary)]/5 p-5"
            >
              <p className="text-center text-sm text-[var(--text-secondary)]">
                第 {qIndex + 1} / {QUESTIONS.length} 题
              </p>
              <p className="mt-2 text-center text-lg font-bold text-[var(--text)]">
                {QUESTIONS[qIndex].prompt}
              </p>

              <div className="mt-4 grid grid-cols-2 gap-3">
                {QUESTIONS[qIndex].options.map((opt, i) => (
                  <button
                    key={i}
                    onClick={() => handleAnswer(opt.correct)}
                    className="rounded-xl border border-[var(--border)] bg-[var(--bg-card)] px-4 py-3 text-sm font-medium text-[var(--text)] transition-all hover:-translate-y-0.5 hover:border-[var(--primary-light)] hover:bg-[var(--bg-soft)]"
                  >
                    {opt.label}
                  </button>
                ))}
              </div>

              {encourage && (
                <p className="mt-4 animate-float-in text-center text-sm text-[var(--text-secondary)]">
                  {encourage}
                  <span className="ml-1 text-[var(--text-muted)]">
                    （{QUESTIONS[qIndex].hint}）
                  </span>
                </p>
              )}
            </div>
          </section>
        )}

        {/* ===== 完成 ===== */}
        {phase === "done" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="animate-bounce-soft text-5xl">🏆</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你学会了画条形图，也会从图里读出信息！
            </p>

            {/* 小结卡片 */}
            <div className="mx-auto mt-6 max-w-sm rounded-xl border-2 border-[var(--primary)] bg-[var(--primary)]/10 p-4">
              <p className="text-center text-sm font-bold text-[var(--text)]">
                条形图小本领
              </p>
              <p className="mt-1 text-center text-xs text-[var(--text-secondary)]">
                画图：一格代表 1 个　·　读图：看条形顶部对准几
              </p>
            </div>

            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <button
                onClick={resetAll}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再练一次
              </button>
              {nextStep ? (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  下一步：{nextStep.label} →
                </Link>
              ) : (
                <Link
                  href="/learn/data"
                  className="rounded-full border border-[var(--border)] px-6 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
                >
                  ← 回到学习路径
                </Link>
              )}
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}
